type UserSwatch = { background: string; text: string };

const DEFAULT_USER_COLOR: UserSwatch = { background: "#ECEFF4", text: palette.slate };
const GOLDEN_ANGLE_DEGREES = 137.508;

const createDistinctUserSwatch = (index: number): UserSwatch => {
  const hue = Math.round((Math.abs(index) * GOLDEN_ANGLE_DEGREES) % 360);
  const lightness = index % 2 === 0 ? 44 : 52;
  const background = `hsl(${hue} 78% ${lightness}%)`;
  const useDarkText = (hue >= 42 && hue <= 86) || lightness >= 58;
  return { background, text: useDarkText ? "#111827" : "#FFFFFF" };
};

const buildUserColorMap = (userIds: Array<number | null | undefined>): Map<number, UserSwatch> => {
  const uniqueIds = Array.from(
    new Set(
      userIds.filter((id): id is number => typeof id === "number" && Number.isFinite(id)),
    ),
  ).sort((a, b) => a - b);
  const map = new Map<number, UserSwatch>();
  uniqueIds.forEach((userId, index) => {
    map.set(userId, createDistinctUserSwatch(index));
  });
  return map;
};

const formatShiftTimeRange = (start?: string | null, end?: string | null) => {
  const first = (start ?? "").trim().replace(/^(\d{1,2}:\d{2}).*$/, "$1");
  const second = (end ?? "").trim().replace(/^(\d{1,2}:\d{2}).*$/, "$1");
  if (!first && !second) {
    return "";
  }
  if (!first) {
    return second;
  }
  if (!second) {
    return first;
  }
  return `${first} \u2013 ${second}`;
};

const isPubCrawlShiftInstance = (instance: ShiftInstance) => {
  const typeKey = instance.shiftType?.key?.toLowerCase() ?? "";
  const typeName = instance.shiftType?.name?.toLowerCase() ?? "";
  const templateName = instance.template?.name?.toLowerCase() ?? "";
  if (typeKey === "private_pub_crawl") {
    return false;
  }
  if (typeKey === "pub_crawl") {
    return true;
  }

  if (typeName.includes("private pub crawl") || templateName.includes("private pub crawl")) {
    return false;
  }

  return typeName.includes("pub crawl") || templateName.includes("pub crawl");
};

const createShiftGroupKey = (instance: ShiftInstance) => {
  const shiftKey = instance.shiftType?.key ?? `type-${instance.shiftTypeId ?? "unknown"}`;
  return `type:${shiftKey}`;
};

const normalizeTimeLabel = (value: string) => {
  const trimmed = value.trim();
  return trimmed.length > 0 ? trimmed : "Any Time";
};

const parseTimeRangeLabel = (value: string) => {
  const normalized = value.trim();
  if (!normalized || normalized === "Any Time") {
    return null;
  }

  const [start, end] = normalized.split(/\s*[–-]\s*/);
  if (!start) {
    return null;
  }

  return {
    start,
    end: end || null,
  };
};

const isPromotionShiftName = (value: string | null | undefined) =>
  value?.toLowerCase().includes("promotion") ?? false;

const hasShiftStartPassed = (shift: ShiftInstance | null | undefined) => {
  if (!shift?.date || !shift.timeStart) {
    return false;
  }
  const start = dayjs(`${shift.date} ${shift.timeStart}`);
  return start.isValid() ? start.isBefore(dayjs()) : false;
};

const getShiftEmoji = (value: string | null | undefined) => {
  const normalized = value?.toLowerCase() ?? "";
  if (normalized.includes("pub crawl")) {
    return "🍻";
  }
  if (normalized.includes("promotion")) {
    return "📣";
  }
  if (normalized.includes("clean")) {
    return "🧹";
  }
  if (normalized.includes("boat")) {
    return "⛵";
  }
  if (normalized.includes("party")) {
    return "🎉";
  }
  return "✨";
};

const getShiftGroupHeading = (shiftTypeName: string) => shiftTypeName;

const getShiftGroupPriority = (shiftTypeName: string) => {
  const combined = shiftTypeName.toLowerCase();
  if (combined.includes("promotion")) {
    return 0;
  }
  if (combined.includes("clean")) {
    return 1;
  }
  return 2;
};

const compareTimeLabels = (a: string, b: string) =>
  a.localeCompare(b, undefined, { numeric: true, sensitivity: "base" });

const normalizeRoleName = (value: string | null | undefined) => value?.trim().toLowerCase() ?? "";

const formatRoleLabel = (value: string | null | undefined) => {
  const normalized = value?.trim();
  if (!normalized) {
    return "";
  }
  return normalized
    .split(/\s+/)
    .map((segment) => segment.charAt(0).toUpperCase() + segment.slice(1))
    .join(" ");
};

const getRoleOrderValue = (assignment: ShiftAssignment, index: number) => {
  const normalized = normalizeRoleName(assignment.roleInShift);
  const base = ROLE_PRIORITY[normalized] ?? ROLE_PRIORITY[normalized.replace(/s$/, "")] ?? 10;
  return base + index / 1000;
};

const shiftRolesMatch = (
  source: ShiftAssignment | null | undefined,
  target: ShiftAssignment | null | undefined,
): boolean => {
  if (!source || !target) {
    return false;
  }
  const sourceRoleId = source.shiftRoleId ?? null;
  const targetRoleId = target.shiftRoleId ?? null;
  if (sourceRoleId !== null || targetRoleId !== null) {
    return sourceRoleId !== null && targetRoleId !== null && sourceRoleId === targetRoleId;
  }
  return normalizeRoleName(source.roleInShift) === normalizeRoleName(target.roleInShift);
};

const getUserDisplayName = (assignment: ShiftAssignment) => {
  if (assignment.assignee) {
    const first = assignment.assignee.firstName ?? "";
    const last = assignment.assignee.lastName ?? "";
    const full = `${first} ${last}`.trim();
    if (full.length > 0) {
      return full;
    }
  }
  if (assignment.userId != null) {
    return `User #${assignment.userId}`;
  }
  return "Unassigned";
};

const getRoleEmoji = (value: string | null | undefined) => {
  const normalized = normalizeRoleName(value);
  return ROLE_EMOJI[normalized] ?? ROLE_EMOJI[normalized.replace(/s$/, "")] ?? "•";
};

const getUserInitials = (assignment: ShiftAssignment) => {
  if (assignment.assignee) {
    const first = assignment.assignee.firstName?.trim();
    const last = assignment.assignee.lastName?.trim();
    const initials = `${first?.[0] ?? ""}${last?.[0] ?? ""}`.toUpperCase();
    if (initials) {
      return initials;
    }
  }
  return "?";
};

const getUserProfilePhotoUrl = (assignment: ShiftAssignment) =>
  buildUserProfilePhotoUrl({ user: assignment.assignee ?? null });

const groupAssignmentsByUser = (assignments: ShiftAssignment[]) => {
  const map = new Map<number | string, ShiftAssignment[]>();
  assignments.forEach((assignment, index) => {
    const key = assignment.userId ?? `assignment-${assignment.id}`;
    const existing = map.get(key);
    if (existing) {
      existing.push(assignment);
    } else {
      map.set(key, [assignment]);
    }
  });
  return Array.from(map.values()).map((userAssignments) =>
    userAssignments
      .map((assignment, index) => ({ assignment, index }))
      .sort(
        (a, b) => getRoleOrderValue(a.assignment, a.index) - getRoleOrderValue(b.assignment, b.index),
      )
      .map(({ assignment }) => assignment),
  );
};

const filterAssignmentsForRole = (roleLabel: string, assignments: ShiftAssignment[]) => {
  switch (roleLabel) {
    case "Guides":
      return assignments.filter((assignment) => normalizeRoleName(assignment.roleInShift).includes("guide"));
    case "Social Media":
      return assignments.filter((assignment) => normalizeRoleName(assignment.roleInShift).includes("social"));
    case "Leader":
      return assignments.filter((assignment) => normalizeRoleName(assignment.roleInShift).includes("leader"));
    default:
      return assignments.filter((assignment) => {
        const normalized = normalizeRoleName(assignment.roleInShift);
        return normalized.includes("manager") || normalized.includes("takes");
      });
  }
};

const getUserColor = (
  userId: number | null | undefined,
  userColorMap?: Map<number, UserSwatch>,
): UserSwatch => {
  if (userId == null || !Number.isFinite(userId)) {
    return DEFAULT_USER_COLOR;
  }
  if (userColorMap?.has(userId)) {
    return userColorMap.get(userId) ?? DEFAULT_USER_COLOR;
  }
  return createDistinctUserSwatch(Math.abs(Math.trunc(userId)));
};

const ISO_WEEK_VALUE_REGEX = /^(\d{4})-W(\d{1,2})$/;

const ensureIsoWeekString = (value: Dayjs | string): string => {
  if (typeof value === "string") {
    const trimmed = value.trim();
    const match = ISO_WEEK_VALUE_REGEX.exec(trimmed);
    if (match) {
      const [, rawYear, rawWeek] = match;
      const year = Number(rawYear);
      const week = Number(rawWeek);
      if (!Number.isNaN(year) && !Number.isNaN(week)) {
        return `${year}-W${week.toString().padStart(2, "0")}`;
      }
    }
    const parsed = dayjs(value);
    if (parsed.isValid()) {
      return ensureIsoWeekString(parsed);
    }
    return trimmed;
  }

  const year = value.isoWeekYear();
  const week = value.isoWeek();
  return `${year}-W${week.toString().padStart(2, "0")}`;
};

const parseIsoWeekStart = (value: string | Dayjs | null | undefined): Dayjs | null => {
  if (!value) {
    return null;
  }
  if (dayjs.isDayjs(value)) {
    return value.startOf("isoWeek");
  }
  const parsed = dayjs(value, "GGGG-[W]WW", true);
  return parsed.isValid() ? parsed.startOf("isoWeek") : null;
};

type MonthSegment = { label: string; span: number; key: string };

const buildMonthSegments = (days: Dayjs[]): MonthSegment[] => {
  const segments: { label: string; span: number; month: number; year: number }[] = [];
  days.forEach((day) => {
    const month = day.month();
    const year = day.year();
    const monthLabel = day.format("MMMM").toUpperCase();
    const existing = segments[segments.length - 1];
    if (existing && existing.month === month && existing.year === year) {
      existing.span += 1;
    } else {
      segments.push({ label: monthLabel, span: 1, month, year });
    }
  });
  return segments.map(({ label, span, year, month }) => ({
    label,
    span,
    key: `${year}-${month}`,
  }));
};

const formatWeekValue = (value: string | null | undefined) => {
  if (!value) {
    return "N/A";
  }
  const match = ISO_WEEK_VALUE_REGEX.exec(value);
  if (match) {
    const [, rawYear, rawWeek] = match;
    return formatScheduleWeekLabel(Number(rawYear), Number(rawWeek));
  }
  const parsed = dayjs(value);
  if (parsed.isValid()) {
    return formatScheduleWeekLabel(parsed.isoWeekYear(), parsed.isoWeek());
  }
  return value;
};

const ScheduleOverviewPage = () => {
  const isMobile = useMediaQuery("(max-width: 768px)");
  const canUseSpaciousSwapLayout = useMediaQuery("(max-width: 768px) and (min-height: 620px)");
  const [selectedWeek, setSelectedWeek] = useState<string>("");
  const loggedUserId = useAppSelector((state) => state.session.loggedUserId);
  const todayMobileCardRef = useRef<HTMLDivElement | null>(null);
  const mobileAutoScrolledRef = useRef(false);
  const scheduleWeeksQuery = useScheduleWeeks({ limit: 120 });
  const createSwap = useCreateSwap();
  const mySwaps = useMySwaps();
  const [quickSwapTarget, setQuickSwapTarget] = useState<ShiftAssignment | null>(null);
  const [quickSwapSourceId, setQuickSwapSourceId] = useState<string | null>(null);
  const [quickSwapError, setQuickSwapError] = useState<string | null>(null);
  const weekOptions = useMemo(() => {
    const existingWeeks = (scheduleWeeksQuery.data ?? []) as ScheduleWeek[];
    const options: { value: string; label: string }[] = existingWeeks.map((weekRecord) => ({
      value: ensureIsoWeekString(`${weekRecord.year}-W${weekRecord.isoWeek.toString().padStart(2, "0")}`),
      label: formatScheduleWeekLabel(weekRecord.year, weekRecord.isoWeek),
    }));
    options.sort((a, b) => {
      const aStart = parseIsoWeekStart(a.value);
      const bStart = parseIsoWeekStart(b.value);
      if (!aStart || !bStart) {
        return 0;
      }
      return aStart.valueOf() - bStart.valueOf();
    });
    return options;
  }, [scheduleWeeksQuery.data]);

  useEffect(() => {
    if (!weekOptions.length) {
      return;
    }
    if (selectedWeek && weekOptions.some((option) => option.value === selectedWeek)) {
      return;
    }
     const currentWeekValue = ensureIsoWeekString(dayjs());
        const fallback =
          weekOptions.find((option) => option.value === currentWeekValue)?.value ??
          weekOptions[weekOptions.length - 1]?.value ??
          weekOptions[0]?.value ??
          "";
    if (fallback) {
      setSelectedWeek(fallback);
    }
  }, [weekOptions, selectedWeek]);

  const ensureWeekQuery = useEnsureWeek(selectedWeek || null, { allowGenerate: false, enabled: Boolean(selectedWeek) });
  const weekId = ensureWeekQuery.data?.week?.id ?? null;
  const currentWeekValue = useMemo(() => ensureIsoWeekString(dayjs()), []);
  const todayIsoDate = useMemo(() => dayjs().format("YYYY-MM-DD"), []);
  const shiftInstancesQuery = useShiftInstances(weekId);
  const shiftInstances = useMemo(() => shiftInstancesQuery.data ?? [], [shiftInstancesQuery.data]);
  const weekIndex = useMemo(
    () => weekOptions.findIndex((option) => option.value === selectedWeek),
    [weekOptions, selectedWeek],
  );
  const canNavigateBackward = weekIndex > 0;
  const canNavigateForward = weekIndex >= 0 && weekIndex < weekOptions.length - 1;

  const handleNavigateWeek = useCallback(
    (direction: -1 | 1) => {
      if (direction === -1 && !canNavigateBackward) {
        return;
      }
      if (direction === 1 && !canNavigateForward) {
        return;
      }
      if (weekIndex === -1) {
        const adjusted = dayjs(selectedWeek || undefined).add(direction, "week");
        setSelectedWeek(ensureIsoWeekString(adjusted));
        return;
      }
      const nextIndex = weekIndex + direction;
      if (nextIndex < 0 || nextIndex >= weekOptions.length) {
        return;
      }
      setSelectedWeek(weekOptions[nextIndex].value);
    },
    [selectedWeek, canNavigateBackward, canNavigateForward, weekIndex, weekOptions],
  );

  const weekStart = useMemo(() => {
    const [year, weekPart] = selectedWeek.split("-W");
    if (!year || !weekPart) {
      return dayjs().startOf("isoWeek");
    }
    return dayjs().year(Number(year)).isoWeek(Number(weekPart)).startOf("isoWeek");
  }, [selectedWeek]);

  const daysOfWeek = useMemo(
    () => Array.from({ length: 7 }, (_, index) => weekStart.add(index, "day")),
    [weekStart],
  );
  const monthSegments = useMemo<MonthSegment[]>(() => buildMonthSegments(daysOfWeek), [daysOfWeek]);

  const pubCrawlInstances = useMemo(
    () => shiftInstances.filter((instance) => isPubCrawlShiftInstance(instance)),
    [shiftInstances],
  );

  const otherShiftGroups = useMemo(() => {
    const groups = new Map<
      string,
      {
        key: string;
        shiftTypeName: string;
        timeBuckets: Map<string, Map<string, ShiftInstance[]>>;
      }
    >();

    shiftInstances.forEach((instance) => {
      if (isPubCrawlShiftInstance(instance)) {
        return;
      }

      const key = createShiftGroupKey(instance);
      let group = groups.get(key);
      if (!group) {
        group = {
          key,
          shiftTypeName: instance.shiftType?.name ?? "Shift",
          timeBuckets: new Map<string, Map<string, ShiftInstance[]>>(),
        };
        groups.set(key, group);
      }

      const label = normalizeTimeLabel(formatShiftTimeRange(instance.timeStart, instance.timeEnd));
      let bucket = group.timeBuckets.get(label);
      if (!bucket) {
        bucket = new Map<string, ShiftInstance[]>();
        group.timeBuckets.set(label, bucket);
      }

      const dayInstances = bucket.get(instance.date);
      if (dayInstances) {
        dayInstances.push(instance);
      } else {
        bucket.set(instance.date, [instance]);
      }
    });

    return Array.from(groups.values())
      .map((group) => ({
        key: group.key,
        shiftTypeName: group.shiftTypeName,
        heading: getShiftGroupHeading(group.shiftTypeName),
        timeBuckets: Array.from(group.timeBuckets.entries())
          .sort(([a], [b]) => compareTimeLabels(a, b))
          .map(([label, instancesByDate]) => ({
            label,
            instancesByDate,
          })),
      }))
      .sort((a, b) => {
        const priorityDiff = getShiftGroupPriority(a.shiftTypeName) - getShiftGroupPriority(b.shiftTypeName);
        if (priorityDiff !== 0) {
          return priorityDiff;
        }
        const typeCompare = a.shiftTypeName.localeCompare(b.shiftTypeName);
        if (typeCompare !== 0) {
          return typeCompare;
        }
        return a.key.localeCompare(b.key);
      });
  }, [shiftInstances]);

  const assignmentsByDate = useMemo(() => {
    const map = new Map<string, ShiftAssignment[]>();
    pubCrawlInstances.forEach((instance) => {
      if (!instance.assignments?.length) {
        return;
      }
      const instanceAssignments = instance.assignments.map((assignment) => ({
        ...assignment,
        shiftInstance: instance,
      }));
      const existing = map.get(instance.date);
      if (existing) {
        existing.push(...instanceAssignments);
      } else {
        map.set(instance.date, instanceAssignments);
      }
    });
    return map;
  }, [pubCrawlInstances]);

  const visibleRoles = useMemo(
    () =>
      ROLE_ORDER.filter((roleLabel) =>
        daysOfWeek.some((day) => {
          const isoDate = day.format("YYYY-MM-DD");
          const assignments = assignmentsByDate.get(isoDate) ?? [];
          return filterAssignmentsForRole(roleLabel, assignments).length > 0;
        }),
      ),
    [assignmentsByDate, daysOfWeek],
  );

  const pubCrawlHeading = useMemo(() => {
    if (pubCrawlInstances.length === 0) {
      return "PUB CRAWL";
    }
    const timeLabels = new Set<string>();
    pubCrawlInstances.forEach((instance) => {
      const label = formatShiftTimeRange(instance.timeStart, instance.timeEnd);
      if (label) {
        timeLabels.add(label);
      }
    });
    const suffix = timeLabels.size === 1 ? Array.from(timeLabels)[0] : null;
    return suffix ? `PUB CRAWL - ${suffix}` : "PUB CRAWL";
  }, [pubCrawlInstances]);
  const userColorMap = useMemo(() => {
    const userIds: Array<number | null | undefined> = [];
    shiftInstances.forEach((instance) => {
      instance.assignments?.forEach((assignment) => {
        userIds.push(assignment.userId);
      });
    });
    return buildUserColorMap(userIds);
  }, [shiftInstances]);

  const myAssignmentsForWeek = useMemo(() => {
    if (!loggedUserId) {
      return [];
    }
    const items: Array<ShiftAssignment & { shiftInstance: ShiftInstance }> = [];
    shiftInstances.forEach((instance) => {
      (instance.assignments ?? []).forEach((assignment) => {
        if (assignment.userId === loggedUserId) {
          items.push({
            ...assignment,
            shiftInstance: instance,
          });
        }
      });
    });
    return items;
  }, [loggedUserId, shiftInstances]);

  const quickSwapLimitReachedTypes = useMemo(() => {
    const blocked = new Set<number>();
    if (!mySwaps.data || !weekId || !loggedUserId) {
      return blocked;
    }
    mySwaps.data.forEach((swap) => {
      if (swap.requesterId !== loggedUserId) {
        return;
      }
      const shiftTypeId = swap.fromAssignment?.shiftInstance?.shiftTypeId ?? null;
      const swapWeekId = swap.fromAssignment?.shiftInstance?.scheduleWeekId ?? null;
      if (!shiftTypeId || swapWeekId !== weekId) {
        return;
      }
      if (swap.status === "canceled" || swap.status === "denied") {
        return;
      }
      blocked.add(shiftTypeId);
    });
    return blocked;
  }, [loggedUserId, mySwaps.data, weekId]);

  const getEligibleQuickSwapSources = useCallback(
    (target: ShiftAssignment | null | undefined) => {
      const targetShift = target?.shiftInstance;
      if (!target || !targetShift || !target.assignee || !loggedUserId || target.userId === loggedUserId) {
        return [];
      }
      if (hasShiftStartPassed(targetShift)) {
        return [];
      }
      if (quickSwapLimitReachedTypes.has(targetShift.shiftTypeId)) {
        return [];
      }

      return myAssignmentsForWeek.filter(
        (source) =>
          source.shiftInstance.shiftTypeId === targetShift.shiftTypeId &&
          source.shiftInstanceId !== target.shiftInstanceId &&
          !hasShiftStartPassed(source.shiftInstance) &&
          source.id !== target.id &&
          shiftRolesMatch(source, target),
      );
    },
    [loggedUserId, myAssignmentsForWeek, quickSwapLimitReachedTypes],
  );

  const quickSwapSourceOptions = useMemo(
    () =>
      getEligibleQuickSwapSources(quickSwapTarget).map((assignment) => ({
        value: assignment.id.toString(),
        label: `${dayjs(assignment.shiftInstance.date).format("ddd, MMM D")} · ${formatShiftTimeRange(
          assignment.shiftInstance.timeStart,
          assignment.shiftInstance.timeEnd,
        )} · ${formatRoleLabel(assignment.roleInShift)}`,
      })),
    [getEligibleQuickSwapSources, quickSwapTarget],
  );

  const selectedQuickSwapSource = useMemo(
    () =>
      quickSwapSourceId
        ? myAssignmentsForWeek.find((assignment) => assignment.id.toString() === quickSwapSourceId) ?? null
        : null,
    [myAssignmentsForWeek, quickSwapSourceId],
  );

  const loading = ensureWeekQuery.isLoading || shiftInstancesQuery.isLoading;
  const error = ensureWeekQuery.isError ? ensureWeekQuery.error : shiftInstancesQuery.error;
  const hasWeek = Boolean(weekId);

  useEffect(() => {
    mobileAutoScrolledRef.current = false;
  }, [selectedWeek]);

  useEffect(() => {
    if (!isMobile) {
      return;
    }
    if (loading || !hasWeek) {
      return;
    }
    if (selectedWeek !== currentWeekValue) {
      return;
    }
    if (mobileAutoScrolledRef.current) {
      return;
    }

    const target = todayMobileCardRef.current;
    if (!target) {
      return;
    }

    mobileAutoScrolledRef.current = true;
    window.requestAnimationFrame(() => {
      target.scrollIntoView({ behavior: "smooth", block: "start" });
    });
  }, [currentWeekValue, hasWeek, isMobile, loading, selectedWeek, shiftInstances.length]);

  const handleOpenQuickSwap = (target: ShiftAssignment) => {
    const sources = getEligibleQuickSwapSources(target);
    if (sources.length === 0) {
      return;
    }
    setQuickSwapTarget(target);
    setQuickSwapSourceId(sources.length === 1 ? sources[0].id.toString() : null);
    setQuickSwapError(null);
  };

  const handleCloseQuickSwap = () => {
    if (createSwap.isPending) {
      return;
    }
    setQuickSwapTarget(null);
    setQuickSwapSourceId(null);
    setQuickSwapError(null);
  };

  const handleConfirmQuickSwap = async () => {
    if (!quickSwapTarget?.userId || !quickSwapSourceId) {
      return;
    }
    setQuickSwapError(null);
    try {
      await createSwap.mutateAsync({
        fromAssignmentId: Number(quickSwapSourceId),
        toAssignmentId: quickSwapTarget.id,
        partnerId: quickSwapTarget.userId,
      });
      handleCloseQuickSwap();
    } catch (error) {
      setQuickSwapError(error instanceof Error ? error.message : "Could not request this swap.");
    }
  };

  const renderQuickSwapAssignmentCard = (
    assignment: (ShiftAssignment & { shiftInstance?: ShiftInstance | null }) | null,
    label: string,
    tone: "offer" | "request",
  ) => {
    if (!assignment) {
      return (
        <Box
          style={{
            width: "100%",
            borderRadius: 18,
            border: "2px dashed #CBD5E1",
            padding: 16,
            textAlign: "center",
            backgroundColor: "#F8FAFC",
          }}
        >
          <Text fw={900} c="dimmed" style={{ fontFamily: HEADER_FONT_STACK }}>
            Select your shift
          </Text>
        </Box>
      );
    }

    const shift = assignment.shiftInstance ?? null;
    const accent = tone === "offer" ? "#2563EB" : "#e90183";
    const borderColor = tone === "offer" ? "#93C5FD" : "#F9A8D4";
    const headerBackground =
      tone === "offer"
        ? "linear-gradient(135deg, rgba(37, 99, 235, 0.16), rgba(147, 197, 253, 0.18))"
        : "linear-gradient(135deg, rgba(233, 1, 131, 0.16), rgba(244, 114, 182, 0.16))";
    const softBackground =
      tone === "offer"
        ? "linear-gradient(180deg, rgba(239, 246, 255, 0.98), rgba(255, 255, 255, 0.98))"
        : "linear-gradient(180deg, rgba(253, 242, 248, 0.98), rgba(255, 255, 255, 0.98))";
    const timeRange = formatShiftTimeRange(shift?.timeStart, shift?.timeEnd);
    const photoUrl = getUserProfilePhotoUrl(assignment);
    const spacious = canUseSpaciousSwapLayout;
    const desktopCompact = !isMobile;

    return (
      <Box
        style={{
          width: "100%",
          minHeight: isMobile ? "clamp(166px, 25dvh, 194px)" : undefined,
            borderRadius: isMobile ? 16 : 16,
          border: `2px solid ${borderColor}`,
          background: softBackground,
          overflow: "hidden",
            boxShadow: isMobile ? "0 8px 18px rgba(15, 23, 42, 0.08)" : "0 10px 20px rgba(15, 23, 42, 0.08)",
        }}
      >
        <Box
          style={{
            padding: spacious ? "9px 12px" : isMobile ? "8px 10px" : "6px 9px",
            textAlign: "center",
            background: headerBackground,
            borderBottom: `1px solid ${borderColor}`,
          }}
        >
          <Text
            fw={900}
            style={{
              fontFamily: HEADER_FONT_STACK,
              color: accent,
              letterSpacing: "0.1em",
              textTransform: "uppercase",
              fontSize: spacious ? 13 : isMobile ? 12 : 12,
            }}
          >
            {label}
          </Text>
        </Box>

        <Stack gap={spacious ? 8 : isMobile ? 7 : 6} align="center" justify="center" style={{ minHeight: isMobile ? "calc(100% - 34px)" : undefined, padding: spacious ? 10 : isMobile ? 9 : 8 }}>
          <Group gap={spacious ? 10 : isMobile ? 8 : 7} align="center" justify="center" wrap="nowrap" style={{ width: "100%" }}>
            <Avatar
              src={photoUrl ?? undefined}
              alt={getUserDisplayName(assignment)}
              size={spacious ? 50 : isMobile ? 46 : 38}
              radius="xl"
              styles={{
                root: {
                  border: "2px solid #FFFFFF",
                  outline: `2px solid ${accent}`,
                  boxShadow: "0 8px 18px rgba(15, 23, 42, 0.14)",
                  fontFamily: HEADER_FONT_STACK,
                  fontWeight: 900,
                  color: accent,
                },
              }}
            >
              {getUserInitials(assignment)}
            </Avatar>
            <Stack gap={2} align="center" style={{ minWidth: 0 }}>
              <Text
                fw={900}
                ta="center"
                style={{
                  fontFamily: HEADER_FONT_STACK,
                  color: palette.slate,
                  fontSize: spacious ? 16 : isMobile ? 14 : 13,
                  lineHeight: 1.1,
                }}
              >
                {getUserDisplayName(assignment)}
              </Text>
              <Badge variant="light" color={tone === "offer" ? "blue" : "violet"} radius="xl" size={spacious ? "sm" : "xs"}>
                {formatRoleLabel(assignment.roleInShift)}
              </Badge>
            </Stack>
          </Group>

          <Box style={{ width: "100%", textAlign: "center" }}>
            <Text
              fw={900}
              style={{
                fontFamily: HEADER_FONT_STACK,
                color: accent,
                letterSpacing: "0.08em",
                textTransform: "uppercase",
                fontSize: spacious ? 19 : isMobile ? 17 : 15,
                lineHeight: 1,
              }}
            >
              {shift?.shiftType?.name ?? "Shift"}
            </Text>
          </Box>

          <Box
            style={{
              width: "100%",
              display: "grid",
              gridTemplateColumns: "1fr 1fr",
              gap: spacious ? 10 : desktopCompact ? 6 : 8,
            }}
          >
            <Box
              style={{
                borderRadius: 14,
                backgroundColor: "#FFFFFF",
                border: "1px solid #E2E8F0",
                padding: spacious ? "8px 8px" : isMobile ? "7px 6px" : "6px 6px",
                textAlign: "center",
              }}
            >
              <Text size="xs" fw={900} c="dimmed" style={{ fontFamily: HEADER_FONT_STACK }}>
                DATE
              </Text>
              <Text fw={900} style={{ fontFamily: HEADER_FONT_STACK, fontSize: spacious ? 15 : isMobile ? 14 : 12 }}>
                {shift?.date ? dayjs(shift.date).format("ddd, MMM D") : "N/A"}
              </Text>
            </Box>
            <Box
              style={{
                borderRadius: 14,
                backgroundColor: "#FFFFFF",
                border: "1px solid #E2E8F0",
                padding: spacious ? "8px 8px" : isMobile ? "7px 6px" : "6px 6px",
                textAlign: "center",
              }}
            >
              <Text size="xs" fw={900} c="dimmed" style={{ fontFamily: HEADER_FONT_STACK }}>
                TIME
              </Text>
              <Text fw={900} style={{ fontFamily: HEADER_FONT_STACK, fontSize: spacious ? 15 : isMobile ? 14 : 12 }}>
                {timeRange || "Any time"}
              </Text>
            </Box>
          </Box>
        </Stack>
      </Box>
    );
  };

  const renderAssignmentGroupCard = (
    groupAssignments: ShiftAssignment[],
    options?: { showRoles?: boolean; variant?: "default" | "mobile" },
  ) => {
    const primary = groupAssignments[0];
    const { background, text } = getUserColor(primary?.userId ?? null, userColorMap);
    const name = getUserDisplayName(primary);
    const photoUrl = primary ? getUserProfilePhotoUrl(primary) : null;
    const initials = primary ? getUserInitials(primary) : "?";
    const styles = createUserCardStyles(background);
    const secondaryColor =
      text.toLowerCase() === "#ffffff" ? "rgba(255, 255, 255, 0.78)" : lightenColor(text, 0.35);
    const showRoles = options?.showRoles ?? false;
    const variant = options?.variant ?? "default";
    const roleLabels = showRoles
      ? Array.from(
          groupAssignments
            .map((assignment) => {
              const formatted = formatRoleLabel(assignment.roleInShift);
              const normalized = normalizeRoleName(assignment.roleInShift);
              return formatted
                ? ({ formatted, normalized } as const)
                : null;
            })
            .filter(
              (
                item,
              ): item is {
                formatted: string;
                normalized: string;
              } => item !== null,
            )
            .reduce<Map<string, string>>((map, item) => {
              if (!map.has(item.normalized)) {
                map.set(item.normalized, item.formatted);
              }
              return map;
            }, new Map())
            .values(),
        )
      : [];
    const showCount = groupAssignments.length > 1;
    const quickSwapSources = primary ? getEligibleQuickSwapSources(primary) : [];
    const canQuickSwap = quickSwapSources.length > 0;

    if (variant === "mobile") {
      return (
        <Card
          key={groupAssignments.map((assignment) => assignment.id).join("-")}
          radius={18}
          withBorder
          padding={0}
          style={{
            width: "100%",
            backgroundColor: "#FFFFFF",
            borderColor: "rgba(148, 163, 184, 0.28)",
            borderLeft: `6px solid ${background}`,
            boxShadow: "0 8px 18px rgba(46, 52, 70, 0.08)",
            overflow: "hidden",
            position: "relative",
          }}
        >
          {canQuickSwap && primary ? (
            <ActionIcon
              aria-label={`Request swap with ${name}`}
              variant="light"
              color="violet"
              radius="xl"
              size={30}
              onClick={(event) => {
                event.stopPropagation();
                handleOpenQuickSwap(primary);
              }}
              style={{
                position: "absolute",
                top: 8,
                right: 8,
                border: "1px solid rgba(124, 77, 255, 0.22)",
                backgroundColor: "rgba(245, 243, 255, 0.94)",
              }}
            >
              <IconArrowsExchange size={16} />
            </ActionIcon>
          ) : null}
          <Stack gap={8} align="center" style={{ padding: "12px", width: "100%" }}>
              <Avatar
                src={photoUrl ?? undefined}
                alt={name}
                size={46}
                radius="xl"
                color="blue"
                styles={{
                  root: {
                    border: "2px solid #FFFFFF",
                    outline: `2px solid ${background}`,
                    boxShadow: "0 8px 16px rgba(17, 24, 39, 0.12)",
                    backgroundColor: photoUrl ? "#ffffff" : "#F8FAFC",
                    color: palette.plumDark,
                    fontFamily: HEADER_FONT_STACK,
                    fontWeight: 900,
                  },
                }}
              >
                {initials}
              </Avatar>
              <Stack gap={4} align="center" style={{ width: "100%", minWidth: 0 }}>
                <Text
                  fw={900}
                  truncate
                  style={{
                    fontFamily: HEADER_FONT_STACK,
                    color: palette.slate,
                    fontSize: 15,
                    letterSpacing: "0.02em",
                    lineHeight: 1.15,
                    textAlign: "center",
                    width: "100%",
                  }}
                >
                  {name}
                </Text>
                <Group gap={6} justify="center" wrap="wrap">
                  {showRoles && roleLabels.length > 0
                    ? roleLabels.map((label) => (
                        <Badge key={label} size="xs" radius="xl" variant="light" color="violet">
                          {label}
                        </Badge>
                      ))
                    : null}
                  {showCount ? (
                    <Badge size="xs" radius="xl" variant="light" color="gray">
                      {groupAssignments.length} shifts
                    </Badge>
                  ) : null}
                </Group>
              </Stack>
          </Stack>
        </Card>
      );
    }

    return (
      <Card
        key={groupAssignments.map((assignment) => assignment.id).join("-")}
        radius="lg"
        withBorder
        padding={0}
        style={{ ...styles.container, color: text }}
      >
        <Box style={styles.overlay} />
        {canQuickSwap && primary ? (
          <ActionIcon
            aria-label={`Request swap with ${name}`}
            variant="light"
            color="violet"
            radius="xl"
            size={24}
            onClick={(event) => {
              event.stopPropagation();
              handleOpenQuickSwap(primary);
            }}
            style={{
              position: "absolute",
              top: 8,
              right: 8,
              zIndex: 2,
              border: "1px solid rgba(124, 77, 255, 0.26)",
              backgroundColor: "rgba(255, 255, 255, 0.9)",
              boxShadow: "0 8px 16px rgba(17, 24, 39, 0.16)",
            }}
          >
            <IconArrowsExchange size={14} />
          </ActionIcon>
        ) : null}
        <Stack gap={8} align="center" style={{ width: "100%", position: "relative", zIndex: 1 }}>
          <Avatar
            src={photoUrl ?? undefined}
            alt={name}
            size={54}
            radius="xl"
            color="blue"
            styles={{
              root: {
                border: "3px solid rgba(255, 255, 255, 0.88)",
                boxShadow: "0 10px 22px rgba(17, 24, 39, 0.22)",
                backgroundColor: photoUrl ? "#ffffff" : "rgba(255, 255, 255, 0.82)",
                color: text.toLowerCase() === "#ffffff" ? palette.plumDark : text,
                fontFamily: HEADER_FONT_STACK,
                fontWeight: 800,
              },
            }}
          >
            {initials}
          </Avatar>
          <Text style={{ ...userCardNameStyles, color: text }}>{name}</Text>
          {showRoles && roleLabels.length > 0 ? (
            <Text size="xs" style={{ fontFamily: HEADER_FONT_STACK, color: secondaryColor }}>
              {roleLabels.join(" \u2022 ")}
            </Text>
          ) : null}
          {showCount ? (
            <Text size="xs" style={{ fontFamily: HEADER_FONT_STACK, color: secondaryColor }}>
              {groupAssignments.length} assignments
            </Text>
          ) : null}
        </Stack>
      </Card>
    );
  };

  const renderAssignmentsForRole = (
    roleLabel: string,
    assignments: ShiftAssignment[],
    options?: { variant?: "default" | "mobile" },
  ): ReactNode[] => {
    const matches = filterAssignmentsForRole(roleLabel, assignments);

    if (matches.length === 0) {
      return [
        <Text
          size={options?.variant === "mobile" ? "xs" : "sm"}
          c="dimmed"
          fw={options?.variant === "mobile" ? 900 : undefined}
          style={{
            fontFamily: HEADER_FONT_STACK,
            letterSpacing: options?.variant === "mobile" ? "0.08em" : undefined,
            textTransform: options?.variant === "mobile" ? "uppercase" : undefined,
          }}
        >
          {options?.variant === "mobile" ? "No one assigned" : "\u2014"}
        </Text>
      ];
    }

    const grouped = groupAssignmentsByUser(matches);

    return grouped.map((groupAssignments) =>
      renderAssignmentGroupCard(groupAssignments, { variant: options?.variant }),
    );
  };

  const renderInstancesForCell = (
    instances: ShiftInstance[],
    options?: {
      showTime?: boolean;
      showRoles?: boolean;
      emphasizeTime?: boolean;
      variant?: "default" | "mobile";
    },
  ) => {
    const showTime = options?.showTime ?? true;
    const showRoles = options?.showRoles ?? true;
    const emphasizeTime = options?.emphasizeTime ?? false;
    const variant = options?.variant ?? "default";
    if (instances.length === 0) {
      return (
        <Text
          size={options?.variant === "mobile" ? "xs" : "sm"}
          c="dimmed"
          fw={options?.variant === "mobile" ? 900 : undefined}
          style={{
            fontFamily: HEADER_FONT_STACK,
            letterSpacing: options?.variant === "mobile" ? "0.08em" : undefined,
            textTransform: options?.variant === "mobile" ? "uppercase" : undefined,
          }}
        >
          {options?.variant === "mobile" ? "No one assigned" : "\u2014"}
        </Text>
      );
    }

    const sorted = [...instances].sort((a, b) => {
      const aStart = a.timeStart ?? "";
      const bStart = b.timeStart ?? "";
      if (aStart && bStart) {
        const compare = aStart.localeCompare(bStart);
        if (compare !== 0) {
          return compare;
        }
      }
      return a.id - b.id;
    });

    return (
      <Stack gap={12} align="center" style={{ width: "100%" }}>
        {sorted.map((instance) => {
          const assignments = (instance.assignments ?? []).map((assignment) => ({
            ...assignment,
            shiftInstance: instance,
          }));
          const grouped = groupAssignmentsByUser(assignments);
          const timeLabel = formatShiftTimeRange(instance.timeStart, instance.timeEnd);

          return (
            <Stack key={`instance-${instance.id}`} gap={8} align="center" style={{ width: "100%" }}>
              {showTime && timeLabel ? (
                <Text
                  size={emphasizeTime ? "sm" : "xs"}
                  fw={emphasizeTime ? 700 : 600}
                  c={emphasizeTime ? palette.slate : "dimmed"}
                  style={{
                    fontFamily: HEADER_FONT_STACK,
                    letterSpacing: emphasizeTime ? "0.02em" : "0.05em",
                  }}
                >
                  {timeLabel}
                </Text>
              ) : null}
              {grouped.length > 0
                ? grouped.map((groupAssignments) =>
                    renderAssignmentGroupCard(groupAssignments, { showRoles, variant }),
                  )
                : (
                    <Text
                      size={variant === "mobile" ? "xs" : "sm"}
                      c="dimmed"
                      fw={variant === "mobile" ? 900 : undefined}
                      style={{
                        fontFamily: HEADER_FONT_STACK,
                        letterSpacing: variant === "mobile" ? "0.08em" : undefined,
                        textTransform: variant === "mobile" ? "uppercase" : undefined,
                      }}
                    >
                      {variant === "mobile" ? "No one assigned" : "\u2014"}
                    </Text>
                  )}
            </Stack>
          );
        })}
      </Stack>
    );
  };

  const renderScheduleTable = (
    key: string,
    heading: string,
    firstColumnLabel: string,
    rows: ReactNode[],
  ) => (
    <Box
      key={key}
      style={{
        flex: 1,
        minWidth: 0,
        overflow: "hidden",
        borderRadius: 20,
        backgroundColor: "#fff",
        boxShadow: palette.tableShadow,
      }}
    >
      <Box
        component="table"
        style={{
          width: "100%",
          maxWidth: "100%",
          minWidth: 0,
          tableLayout: "fixed",
          borderCollapse: "separate",
          borderSpacing: 0,
          borderRadius: 18,
          overflow: "hidden",
        }}
      >
        <thead>
          <tr>
            <th
              colSpan={daysOfWeek.length + 1}
              style={{
                borderTop: `3px solid ${palette.border}`,
                textAlign: "center",
                background: "linear-gradient(135deg, #7C4DFF 0%, #9C6CFF 55%, #F48FB1 100%)",
                padding: "18px",
                fontSize: "22px",
                fontWeight: 800,
                textTransform: "uppercase",
                fontFamily: HEADER_FONT_STACK,
                letterSpacing: "0.05em",
                color: "#fff",
              }}
            >
              {heading}
            </th>
          </tr>
          <tr>
            <th
              style={{
                ...tableCellBase,
                borderWidth: "3px 3px 1px 3px",
                backgroundColor: palette.lavenderBold,
                textAlign: "center",
                padding: "18px 12px",
                verticalAlign: "middle",
                color: palette.plumDark,
              }}
            >
              <div style={yearHeaderLabelStyles}>{weekStart.format("YYYY")}</div>
            </th>
            {monthSegments.map((segment) => (
              <th
                key={`${key}-month-${segment.key}`}
                colSpan={segment.span}
                style={{
                  ...tableCellBase,
                  borderWidth: "3px 3px 1px 0",
                  backgroundColor: palette.lavenderAccent,
                  textAlign: "center",
                  padding: "16px 12px",
                  color: palette.plumDark,
                }}
              >
                <div style={monthHeaderLabelStyles}>{segment.label}</div>
              </th>
            ))}
          </tr>
          <tr>
            <th style={roleHeaderCellStyles}>
              <div style={roleHeaderLabelStyles}>{firstColumnLabel}</div>
            </th>
            {daysOfWeek.map((day, index) => {
              const nextDay = daysOfWeek[index + 1];
              const borderRightWidth = !nextDay || !day.isSame(nextDay, "month") ? "3px" : "1px";
              return (
                <th
                  key={`${key}-date-${day.toString()}`}
                  style={{
                    ...tableCellBase,
                    backgroundColor: palette.lavenderDeep,
                    borderWidth: `3px ${borderRightWidth} 1px 0`,
                  }}
                >
                  <Stack gap={0} align="center">
                    <Text
                      fw={700}
                      size="md"
                      style={{ fontFamily: HEADER_FONT_STACK, fontSize: "18px" }}
                    >
                      {day.format("DD")}
                    </Text>
                    <Text size="xs" c="dimmed" style={{ fontFamily: HEADER_FONT_STACK }}>
                      {day.format("ddd")}
                    </Text>
                  </Stack>
                </th>
              );
            })}
          </tr>
        </thead>
        <tbody>{rows}</tbody>
      </Box>
    </Box>
  );

  const renderMobileSchedule = () => {
    const dayCards = daysOfWeek
      .map((day) => {
        const isoDate = day.format("YYYY-MM-DD");
        const assignments = assignmentsByDate.get(isoDate) ?? [];
        const pubSections = visibleRoles
          .map((roleLabel): { roleLabel: string; nodes: ReactNode[]; assignedCount: number } => {
            const assignedCount = filterAssignmentsForRole(roleLabel, assignments).length;
            return {
              roleLabel,
              assignedCount,
              nodes: renderAssignmentsForRole(roleLabel, assignments, { variant: "mobile" }),
            };
          })
          .filter((section) => section.nodes.length > 0);

        const otherSections = otherShiftGroups
          .flatMap((group) =>
            group.timeBuckets.map((bucket) => {
              const instances = bucket.instancesByDate.get(isoDate) ?? [];
              if (instances.length === 0) {
                return null;
              }
              return {
                key: `${group.key}-${bucket.label}`,
                heading: group.heading,
                label: bucket.label,
                instances,
              };
            }),
          )
          .filter(
            (
              section,
            ): section is {
              key: string;
              heading: string;
              label: string;
              instances: ShiftInstance[];
            } => section !== null,
          );

        if (pubSections.length === 0 && otherSections.length === 0) {
          return null;
        }

        const isToday = selectedWeek === currentWeekValue && isoDate === todayIsoDate;
        return (
          <Card
            key={`mobile-day-${isoDate}`}
            ref={isToday ? todayMobileCardRef : undefined}
            radius={24}
            shadow="xl"
            padding={0}
            withBorder
            style={{
              width: "100%",
              scrollMarginTop: 88,
              background: isToday
                ? "linear-gradient(180deg, #F4ECFF 0%, #FFF7FC 100%)"
                : "linear-gradient(180deg, #F3F0FF 0%, #F8FAFF 100%)",
              borderColor: isToday ? "#8B5CF6" : "#B9C4D8",
              borderWidth: 2,
              boxShadow: isToday
                ? "0 24px 46px rgba(124, 77, 255, 0.26)"
                : "0 22px 42px rgba(46, 52, 70, 0.2)",
              overflow: "hidden",
            }}
          >
            <Box
              style={{
                height: 6,
                background: isToday
                  ? palette.heroGradient
                  : "linear-gradient(90deg, rgba(124, 77, 255, 0.58), rgba(255, 142, 195, 0.5))",
              }}
            />
            <Box
              style={{
                background: isToday
                  ? "linear-gradient(135deg, rgba(124, 77, 255, 0.24) 0%, rgba(255, 142, 195, 0.28) 100%)"
                  : "linear-gradient(135deg, rgba(232, 224, 255, 0.92) 0%, rgba(238, 244, 255, 0.96) 100%)",
                borderBottom: "1px solid rgba(107, 114, 128, 0.18)",
                padding: "16px 16px 14px",
              }}
            >
              <Group align="center" justify="space-between" gap="md" wrap="nowrap">
                <Box
                  style={{
                    flex: "0 0 62px",
                    width: 62,
                    borderRadius: 18,
                    backgroundColor: "#ffffff",
                    border: `1px solid ${isToday ? palette.lavenderBold : "#E1E6F0"}`,
                    boxShadow: "0 10px 22px rgba(46, 52, 70, 0.1)",
                    padding: "8px 6px",
                    textAlign: "center",
                  }}
                >
                  <Text size="xs" fw={800} c="dimmed" style={{ fontFamily: HEADER_FONT_STACK }}>
                    {day.format("MMM").toUpperCase()}
                  </Text>
                  <Text fw={900} style={{ fontFamily: HEADER_FONT_STACK, fontSize: 24, lineHeight: 1 }}>
                    {day.format("DD")}
                  </Text>
                </Box>
                <Stack gap={4} align="center" style={{ flex: "1 1 auto", minWidth: 0 }}>
                  <Group gap={6} justify="center" wrap="wrap">
                    <Text
                      fw={900}
                      style={{
                        fontFamily: HEADER_FONT_STACK,
                        color: palette.slate,
                        lineHeight: 1.08,
                        fontSize: 22,
                        letterSpacing: "0.08em",
                        textTransform: "uppercase",
                      }}
                      ta="center"
                    >
                      {day.format("dddd")}
                    </Text>
                    {isToday ? (
                      <Badge radius="xl" variant="filled" color="violet" size="sm">
                        Today
                      </Badge>
                    ) : null}
                  </Group>
                </Stack>
              </Group>
            </Box>

            <Stack
              gap={14}
              align="center"
              style={{
                width: "100%",
                padding: pubSections.length > 0 ? "0 14px 14px" : 14,
                backgroundColor: "rgba(255, 255, 255, 0.62)",
              }}
            >
              {pubSections.length > 0 ? (
                <Box
                  style={{
                    width: "calc(100% + 28px)",
                    margin: "0 -14px",
                    padding: "16px 14px",
                    background:
                      "linear-gradient(180deg, rgba(237, 229, 255, 0.98), rgba(255, 244, 250, 0.94))",
                    borderTop: "2px solid rgba(124, 77, 255, 0.22)",
                    borderBottom: "2px solid rgba(124, 77, 255, 0.22)",
                  }}
                >
                  <Box
                    style={{
                      padding: "0 4px 14px",
                      textAlign: "center",
                    }}
                  >
                    <Box
                      style={{
                        display: "grid",
                        gridTemplateColumns: "48px minmax(0, 1fr) 48px",
                        alignItems: "center",
                        width: "100%",
                      }}
                    >
                      <Text aria-hidden style={{ fontSize: 34, lineHeight: 1, textAlign: "center" }}>
                        {getShiftEmoji("Pub Crawl")}
                      </Text>
                      <Text
                        fw={900}
                        style={{
                          fontFamily: HEADER_FONT_STACK,
                          color: "#e90183",
                          letterSpacing: "0.1em",
                          textTransform: "uppercase",
                          fontSize: 25,
                          lineHeight: 1,
                          textAlign: "center",
                          whiteSpace: "nowrap",
                        }}
                      >
                        Pub Crawl
                      </Text>
                      <Text aria-hidden style={{ fontSize: 34, lineHeight: 1, textAlign: "center" }}>
                        {getShiftEmoji("Pub Crawl")}
                      </Text>
                    </Box>
                  </Box>
                  <Stack gap={16} align="center" style={{ width: "100%" }}>
                    {pubSections.map((section) => (
                      <Box
                        key={`pub-${isoDate}-${section.roleLabel}`}
                        style={{
                          width: "100%",
                          padding: "12px",
                          borderRadius: 18,
                          background:
                            "linear-gradient(180deg, rgba(232, 224, 255, 0.98), rgba(248, 243, 255, 0.94))",
                          border: "2px solid rgba(124, 77, 255, 0.32)",
                          boxShadow: "0 10px 22px rgba(124, 77, 255, 0.12)",
                        }}
                      >
                        <Box
                          style={{
                            margin: "-12px -12px 0",
                            padding: "10px 12px",
                            borderBottom: "2px solid rgba(124, 77, 255, 0.28)",
                            background:
                              "linear-gradient(135deg, rgba(124, 77, 255, 0.14), rgba(255, 142, 195, 0.12))",
                            position: "relative",
                          }}
                        >
                          <Group gap={6} justify="center" wrap="nowrap" style={{ minWidth: 0 }}>
                              <Text size="sm" aria-hidden>
                                {getRoleEmoji(section.roleLabel)}
                              </Text>
                              <Text
                                fw={800}
                                ta="center"
                                style={{
                                  fontFamily: HEADER_FONT_STACK,
                                  color: "#5B21B6",
                                  fontSize: 14,
                                  letterSpacing: "0.08em",
                                  textTransform: "uppercase",
                                  lineHeight: 1,
                                }}
                              >
                                {section.roleLabel}
                              </Text>
                            </Group>
                            {section.assignedCount > 0 ? (
                              <Text
                                size="sm"
                                c="dimmed"
                                ta="right"
                                style={{
                                  fontFamily: HEADER_FONT_STACK,
                                  whiteSpace: "nowrap",
                                  position: "absolute",
                                  right: 12,
                                  top: "50%",
                                  transform: "translateY(-50%)",
                                  textTransform: "none",
                                  fontWeight: 800,
                                }}
                              >
                                {section.nodes.length} {section.nodes.length === 1 ? "person" : "people"}
                              </Text>
                            ) : null}
                        </Box>
                        <Stack gap={10} align="center" style={{ width: "100%", padding: "12px 0 0" }}>
                            {section.nodes.map((node, index) => (
                              <Box
                                key={`pub-${isoDate}-${section.roleLabel}-node-${index}`}
                                style={{ width: "100%", display: "flex", justifyContent: "center" }}
                              >
                                {node}
                              </Box>
                            ))}
                        </Stack>
                      </Box>
                    ))}
                  </Stack>
                </Box>
              ) : null}

              {otherSections.map((section) => {
                const isPromotion = isPromotionShiftName(section.heading);
                const timeRange = parseTimeRangeLabel(section.label);

                return (
                  <Box
                    key={`other-${isoDate}-${section.key}`}
                    style={{
                      width: "100%",
                      borderRadius: 18,
                      padding: "12px",
                      background: isPromotion
                        ? "linear-gradient(180deg, rgba(255, 237, 213, 0.98), rgba(255, 247, 237, 0.98))"
                        : "linear-gradient(180deg, rgba(226, 232, 240, 0.98), rgba(248, 250, 252, 0.98))",
                      border: isPromotion ? "2px solid rgba(249, 115, 22, 0.36)" : "2px solid rgba(71, 85, 105, 0.34)",
                      boxShadow: isPromotion
                        ? "0 12px 26px rgba(234, 88, 12, 0.14)"
                        : "0 12px 26px rgba(51, 65, 85, 0.12)",
                    }}
                  >
                    <Box
                      style={{
                        margin: "-12px -12px 0",
                        borderBottom: isPromotion
                          ? "2px solid rgba(249, 115, 22, 0.26)"
                          : "2px solid rgba(71, 85, 105, 0.22)",
                        padding: "11px 12px",
                        background: isPromotion
                          ? "linear-gradient(135deg, rgba(249, 115, 22, 0.18), rgba(251, 191, 36, 0.12))"
                          : "linear-gradient(135deg, rgba(71, 85, 105, 0.16), rgba(148, 163, 184, 0.1))",
                      }}
                    >
                      <Stack gap={8} align="center">
                        <Box
                          style={{
                            display: "grid",
                            gridTemplateColumns: "42px minmax(0, 1fr) 42px",
                            alignItems: "center",
                            width: "100%",
                          }}
                        >
                          <Text aria-hidden style={{ fontSize: 26, lineHeight: 1, textAlign: "center" }}>
                            {getShiftEmoji(section.heading)}
                          </Text>
                          <Text
                            fw={900}
                            ta="center"
                            style={{
                              fontFamily: HEADER_FONT_STACK,
                              color: isPromotion ? "#9A3412" : "#334155",
                              letterSpacing: "0.14em",
                              textTransform: "uppercase",
                              fontSize: section.heading.length > 14 ? 18 : 24,
                              lineHeight: 1,
                              textAlign: "center",
                            }}
                          >
                            {section.heading}
                          </Text>
                          <Text aria-hidden style={{ fontSize: 26, lineHeight: 1, textAlign: "center" }}>
                            {getShiftEmoji(section.heading)}
                          </Text>
                        </Box>
                        {timeRange ? (
                          <Group gap="xs" wrap="nowrap" justify="center" style={{ width: "100%" }}>
                            <Box
                              style={{
                                flex: "1 1 0",
                                borderRadius: 12,
                                backgroundColor: "rgba(255, 255, 255, 0.78)",
                                border: isPromotion
                                  ? "1px solid rgba(249, 115, 22, 0.22)"
                                  : "1px solid rgba(71, 85, 105, 0.22)",
                                padding: "7px 8px",
                                textAlign: "center",
                              }}
                            >
                              <Text size="xs" fw={900} c="dimmed" style={{ fontFamily: HEADER_FONT_STACK }}>
                                START
                              </Text>
                              <Text
                                fw={900}
                                style={{
                                  fontFamily: HEADER_FONT_STACK,
                                  color: isPromotion ? "#9A3412" : "#334155",
                                  fontSize: 17,
                                }}
                              >
                                {timeRange.start}
                              </Text>
                            </Box>
                            {timeRange.end ? (
                              <Box
                                style={{
                                  flex: "1 1 0",
                                  borderRadius: 12,
                                  backgroundColor: "rgba(255, 255, 255, 0.78)",
                                  border: isPromotion
                                    ? "1px solid rgba(249, 115, 22, 0.22)"
                                    : "1px solid rgba(71, 85, 105, 0.22)",
                                  padding: "7px 8px",
                                  textAlign: "center",
                                }}
                              >
                                <Text size="xs" fw={900} c="dimmed" style={{ fontFamily: HEADER_FONT_STACK }}>
                                  END
                                </Text>
                                <Text
                                  fw={900}
                                  style={{
                                    fontFamily: HEADER_FONT_STACK,
                                    color: isPromotion ? "#9A3412" : "#334155",
                                    fontSize: 17,
                                  }}
                                >
                                  {timeRange.end}
                                </Text>
                              </Box>
                            ) : null}
                          </Group>
                        ) : (
                          <Text size="xs" c="dimmed" fw={700} style={{ fontFamily: HEADER_FONT_STACK }}>
                            {section.label}
                          </Text>
                        )}
                      </Stack>
                    </Box>
                    <Stack gap={10} align="center" style={{ width: "100%", padding: "10px 0 0" }}>
                      {renderInstancesForCell(section.instances, {
                        showTime: false,
                        showRoles: true,
                        emphasizeTime: false,
                        variant: "mobile",
                      })}
                    </Stack>
                  </Box>
                );
              })}
            </Stack>
          </Card>
        );
      })
      .filter((card): card is JSX.Element => card !== null);

    if (dayCards.length === 0) {
      return (
        <Text size="sm" c="dimmed" ta="center" style={{ fontFamily: HEADER_FONT_STACK }}>
          No shifts scheduled for this week yet.
        </Text>
      );
    }

    return (
      <Stack gap={24} align="center" style={{ width: "100%" }}>
        {dayCards}
      </Stack>
    );
  };

  const pubCrawlRows = visibleRoles.map((roleLabel, roleIndex) => {
    const topBorder = roleIndex === 0 ? "3px" : "2px";
    const bottomBorder = roleIndex === visibleRoles.length - 1 ? "3px" : "1px";
    const roleCellStyle: CSSProperties = {
      ...roleCellStyles,
      borderWidth: `${topBorder} 3px ${bottomBorder} 3px`,
    };
    const assignmentCellStyle: CSSProperties = {
      ...tableCellBase,
      borderWidth: `${topBorder} 1px ${bottomBorder} 0`,
    };

    return (
      <tr key={`role-${roleLabel}`}>
        <td style={roleCellStyle}>
          <div style={roleLabelStyles}>{roleLabel}</div>
        </td>
        {daysOfWeek.map((day, index) => {
          const isoDate = day.format("YYYY-MM-DD");
          const assignments = assignmentsByDate.get(isoDate) ?? [];
          const nextDay = daysOfWeek[index + 1];
          const borderRightWidth = !nextDay || !day.isSame(nextDay, "month") ? "3px" : "1px";
          return (
            <td
              key={`${isoDate}-${roleLabel}`}
              style={{
                ...assignmentCellStyle,
                borderWidth: `${topBorder} ${borderRightWidth} ${bottomBorder} 0`,
              }}
            >
              <Stack gap={8} align="center" style={{ width: "100%" }}>
                {renderAssignmentsForRole(roleLabel, assignments)}
              </Stack>
            </td>
          );
        })}
      </tr>
    );
  });

  const otherShiftTables = otherShiftGroups
    .map((group) => {
      if (group.timeBuckets.length === 0) {
        return null;
      }

      const rows = group.timeBuckets.map((bucket, bucketIndex) => {
        const topBorder = bucketIndex === 0 ? "3px" : "2px";
        const bottomBorder = bucketIndex === group.timeBuckets.length - 1 ? "3px" : "1px";
        const timeframeCellStyle: CSSProperties = {
          ...roleCellStyles,
          borderWidth: `${topBorder} 3px ${bottomBorder} 3px`,
        };
        const assignmentCellStyle: CSSProperties = {
          ...tableCellBase,
          borderWidth: `${topBorder} 1px ${bottomBorder} 0`,
          verticalAlign: "top",
        };

        return (
          <tr key={`${group.key}-${bucket.label}`}>
            <td style={timeframeCellStyle}>
              <div style={roleLabelStyles}>{bucket.label}</div>
            </td>
            {daysOfWeek.map((day, index) => {
              const isoDate = day.format("YYYY-MM-DD");
              const nextDay = daysOfWeek[index + 1];
              const borderRightWidth = !nextDay || !day.isSame(nextDay, "month") ? "3px" : "1px";
              const instances = bucket.instancesByDate.get(isoDate) ?? [];
              return (
                <td
                  key={`${group.key}-${bucket.label}-${isoDate}`}
                  style={{
                    ...assignmentCellStyle,
                    borderWidth: `${topBorder} ${borderRightWidth} ${bottomBorder} 0`,
                  }}
                >
                  {renderInstancesForCell(instances, { showTime: false, showRoles: false })}
                </td>
              );
            })}
          </tr>
        );
      });

      if (rows.length === 0) {
        return null;
      }

      return renderScheduleTable(`group-${group.key}`, group.heading, "Timeframe", rows);
    })
    .filter((table): table is JSX.Element => Boolean(table));

  const pubCrawlTable = renderScheduleTable("pub-crawl", pubCrawlHeading, "Role", pubCrawlRows);
  const hasShiftContent = shiftInstances.length > 0;
  const navigationIsLoading = shiftInstancesQuery.isLoading;
  const weekSelectorWrapperStyle: CSSProperties = isMobile
    ? {
        flex: "1 1 auto",
        minWidth: 0,
        padding: "6px 12px",
        backgroundColor: "rgba(255,255,255,0.18)",
        borderRadius: 14,
        boxShadow: "inset 0 0 0 1px rgba(255,255,255,0.25)",
      }
    : {
        flex: "0 0 240px",
        minWidth: "240px",
        padding: "6px 12px",
        backgroundColor: "rgba(255,255,255,0.18)",
        borderRadius: 14,
        boxShadow: "inset 0 0 0 1px rgba(255,255,255,0.25)",
      };
  const scheduleContent = isMobile
    ? renderMobileSchedule()
    : hasShiftContent
      ? (
        <>
          {pubCrawlTable}
          {otherShiftTables}
        </>
      )
      : null;

  return (
    <Stack mt={isMobile ? "sm" : "lg"} gap="lg">
      {isMobile ? (
        <Group gap="xs" wrap="nowrap" style={{ width: "100%" }}>
          <ActionIcon
            variant="filled"
            color="gray"
            size={46}
            radius="md"
            aria-label="Previous week"
            onClick={() => handleNavigateWeek(-1)}
            disabled={!canNavigateBackward || navigationIsLoading}
            style={{
              flex: "0 0 46px",
              backgroundColor: "#EFF6FF",
              color: "#2563EB",
              border: "3px solid #93C5FD",
              boxShadow: "0 8px 18px rgba(37, 99, 235, 0.18), inset 0 0 0 1px rgba(255,255,255,0.76)",
            }}
          >
            <IconChevronLeft size={18} />
          </ActionIcon>
          <Box style={{ flex: "1 1 auto", minWidth: 0 }}>
            <WeekSelector
              value={selectedWeek || null}
              weeks={weekOptions.map((option) => ({ ...option, label: option.label.toUpperCase() }))}
              onChange={setSelectedWeek}
              selectProps={{
                style: { width: "100%" },
                styles: {
                  input: {
                    fontWeight: 800,
                    textAlign: "center",
                    minHeight: 46,
                    borderRadius: 14,
                    border: "3px solid #94A3B8",
                    boxShadow: "0 8px 18px rgba(15, 23, 42, 0.14), inset 0 0 0 1px rgba(255,255,255,0.82)",
                    textTransform: "uppercase",
                    letterSpacing: "0.04em",
                  },
                  option: {
                    textTransform: "uppercase",
                    letterSpacing: "0.04em",
                  },
                },
              }}
            />
          </Box>
          <ActionIcon
            variant="filled"
            color="gray"
            size={46}
            radius="md"
            aria-label="Next week"
            onClick={() => handleNavigateWeek(1)}
            disabled={!canNavigateForward || navigationIsLoading}
            style={{
              flex: "0 0 46px",
              backgroundColor: "#EFF6FF",
              color: "#2563EB",
              border: "3px solid #93C5FD",
              boxShadow: "0 8px 18px rgba(37, 99, 235, 0.18), inset 0 0 0 1px rgba(255,255,255,0.76)",
            }}
          >
            <IconChevronRight size={18} />
          </ActionIcon>
        </Group>
      ) : (
        <Card
          radius="lg"
          shadow="xl"
          padding="lg"
          style={{
            background: palette.heroGradient,
            color: "#fff",
            overflowX: "hidden",
          }}
        >
          <Stack gap="md" align="center" style={{ width: "100%" }}>
            <Stack gap={6} align="center" style={{ width: "100%" }}>
              <Title order={3} fw={800} ta="center" style={{ fontFamily: HEADER_FONT_STACK }}>
                Weekly Shift Schedule
              </Title>
            </Stack>
            <Group justify="center" gap="sm" wrap="wrap" style={{ width: "100%" }}>
              <Button
                variant="white"
                color="dark"
                leftSection={<IconChevronLeft size={16} />}
                onClick={() => handleNavigateWeek(-1)}
                disabled={!canNavigateBackward || navigationIsLoading}
              >
                Previous
              </Button>
              <Box style={weekSelectorWrapperStyle}>
                <WeekSelector
                  value={selectedWeek || null}
                  weeks={weekOptions}
                  onChange={setSelectedWeek}
                  selectProps={{
                    style: { width: "100%" },
                    styles: {
                      input: {
                        fontWeight: 600,
                        textAlign: "center",
                      },
                    },
                  }}
                />
              </Box>
              <Button
                variant="white"
                color="dark"
                rightSection={<IconChevronRight size={16} />}
                onClick={() => handleNavigateWeek(1)}
                disabled={!canNavigateForward || navigationIsLoading}
              >
                Next
              </Button>
            </Group>
          </Stack>
        </Card>
      )}

      {scheduleWeeksQuery.isError ? (
        <Alert color="red" variant="light" radius="md" title="Unable to load available weeks">
          <Text size="sm">{(scheduleWeeksQuery.error as Error).message}</Text>
        </Alert>
      ) : null}

      {error ? (
        <Alert color="red" variant="light" radius="md" title="Unable to load schedule">
          <Text size="sm">{(error as Error).message}</Text>
        </Alert>
      ) : null}

      {loading ? (
        <Center py="xl">
          <Loader />
        </Center>
      ) : !hasWeek ? (
        <Alert color="yellow" variant="light" radius="md" title="Week not available">
          <Text size="sm">
            Schedule data for {formatWeekValue(selectedWeek)} is not available yet. Generate the week from the builder to
            view assignments.
          </Text>
        </Alert>
      ) : isMobile ? (
        <Stack gap="lg" style={{ width: "100%", minWidth: 0, overflowX: "hidden" }}>
          {scheduleContent}
          {pubCrawlInstances.length === 0 ? (
            <Alert
              mb={0}
              color="yellow"
              variant="light"
              radius="md"
              icon={<IconAlertTriangle size={16} />}
              title="No pub crawl shifts found"
            >
              <Text size="sm">
                There are no assignments for the pub crawl shift during {formatWeekValue(selectedWeek)}.
              </Text>
            </Alert>
          ) : null}
        </Stack>
      ) : (
        <Card
          withBorder
          shadow="xl"
          radius="lg"
          padding="xl"
          style={{ backgroundColor: palette.lavender, borderColor: palette.border, overflow: "hidden" }}
        >
          <Stack gap="xl" style={{ width: "100%", minWidth: 0, overflowX: "hidden" }}>
            {scheduleContent}
            {!hasShiftContent && !isMobile ? (
              <Text size="sm" c="dimmed" ta="center">
                No shifts scheduled for this week yet. Use the actions above to add shifts or auto assign staff.
              </Text>
            ) : null}
            {pubCrawlInstances.length === 0 ? (
              <Alert
                mb={0}
                color="yellow"
                variant="light"
                radius="md"
                icon={<IconAlertTriangle size={16} />}
                title="No pub crawl shifts found"
              >
                <Text size="sm">
                  There are no assignments for the pub crawl shift during {formatWeekValue(selectedWeek)}.
                </Text>
              </Alert>
            ) : null}
          </Stack>
        </Card>
      )}

      <Modal
        opened={Boolean(quickSwapTarget)}
        onClose={handleCloseQuickSwap}
        title={null}
        withCloseButton={false}
        centered
        fullScreen={isMobile}
        radius={isMobile ? 0 : "lg"}
        size="lg"
        styles={{
          body: {
            padding: isMobile ? "10px 12px 12px" : undefined,
          },
        }}
      >
        <Stack
          gap={isMobile ? 10 : "lg"}
          align="center"
          style={{
            minHeight: isMobile ? "calc(100dvh - 24px)" : undefined,
          }}
        >
          {quickSwapTarget ? (
            <>
              <Title
                order={2}
                ta="center"
                style={{
                  width: "100%",
                  fontFamily: HEADER_FONT_STACK,
                  fontWeight: 900,
                  letterSpacing: "0.08em",
                  textTransform: "uppercase",
                  color: palette.slate,
                  fontSize: isMobile ? 24 : 28,
                  lineHeight: 1,
                }}
              >
                Swap request
              </Title>

              <Stack gap={4} align="center" style={{ display: "none" }}>
                <Text fw={900} ta="center" style={{ fontFamily: HEADER_FONT_STACK }}>
                  Swap with {getUserDisplayName(quickSwapTarget)}
                </Text>
                <Text size="sm" c="dimmed" ta="center" style={{ fontFamily: HEADER_FONT_STACK }}>
                  {dayjs(quickSwapTarget.shiftInstance?.date).format("dddd, MMM D")} ·{" "}
                  {quickSwapTarget.shiftInstance?.shiftType?.name ?? "Shift"} ·{" "}
                  {formatShiftTimeRange(
                    quickSwapTarget.shiftInstance?.timeStart,
                    quickSwapTarget.shiftInstance?.timeEnd,
                  )}
                </Text>
                <Badge variant="light" color="violet" radius="xl">
                  {formatRoleLabel(quickSwapTarget.roleInShift)}
                </Badge>
              </Stack>

              {quickSwapSourceOptions.length > 1 ? (
                <Select
                  label="Choose your shift to offer"
                  placeholder="Select your shift"
                  data={quickSwapSourceOptions}
                  value={quickSwapSourceId}
                  onChange={setQuickSwapSourceId}
                  allowDeselect={false}
                  w="100%"
                  styles={{
                    label: { width: "100%", textAlign: "center", fontWeight: 900, fontFamily: HEADER_FONT_STACK },
                    input: {
                      textAlign: "center",
                      minHeight: 46,
                      borderRadius: 14,
                      border: "2px solid #CBD5E1",
                      fontWeight: 800,
                    },
                    option: { justifyContent: "center", textAlign: "center", fontWeight: 700 },
                  }}
                />
              ) : quickSwapSourceOptions.length === 1 ? (
                <Box
                  style={{
                    display: "none",
                    width: "100%",
                    border: "1px solid #D8E1F0",
                    borderRadius: 14,
                    padding: 12,
                    textAlign: "center",
                    backgroundColor: "#F8FAFC",
                  }}
                >
                  <Text size="xs" fw={900} c="dimmed" style={{ fontFamily: HEADER_FONT_STACK }}>
                    YOUR SHIFT TO OFFER
                  </Text>
                  <Text fw={800} style={{ fontFamily: HEADER_FONT_STACK }}>
                    {quickSwapSourceOptions[0].label}
                  </Text>
                </Box>
              ) : (
                <Alert color="yellow" radius="md" title="No matching shift">
                  You do not have a matching shift available for this swap.
                </Alert>
              )}

              <Box
                style={{
                  width: "100%",
                  display: "flex",
                  flexDirection: "column",
                  alignItems: "stretch",
                  gap: canUseSpaciousSwapLayout ? 14 : 8,
                }}
              >
                {renderQuickSwapAssignmentCard(selectedQuickSwapSource, "You offer", "offer")}
                <Center>
                  <Box
                    style={{
                      width: canUseSpaciousSwapLayout ? 42 : isMobile ? 34 : 44,
                      height: canUseSpaciousSwapLayout ? 42 : isMobile ? 34 : 44,
                      borderRadius: "50%",
                      display: "flex",
                      alignItems: "center",
                      justifyContent: "center",
                      backgroundColor: "#111827",
                      color: "#FFFFFF",
                      boxShadow: "0 12px 22px rgba(15, 23, 42, 0.18)",
                    }}
                  >
                    <IconArrowsExchange size={canUseSpaciousSwapLayout ? 22 : isMobile ? 18 : 22} />
                  </Box>
                </Center>
                {renderQuickSwapAssignmentCard(quickSwapTarget, "You request", "request")}
              </Box>

              {quickSwapError ? (
                <Alert color="red" radius="md" w="100%">
                  {quickSwapError}
                </Alert>
              ) : null}

              <Alert
                color="blue"
                radius="md"
                variant="light"
                w="100%"
                mt={isMobile ? "auto" : undefined}
                py={isMobile ? 8 : undefined}
              >
                <Text size={isMobile ? "xs" : "sm"} fw={700} ta="center" style={{ fontFamily: HEADER_FONT_STACK }}>
                  This only sends a request. Nothing changes until both teammate and manager approvals are complete.
                </Text>
              </Alert>

              <Group justify="space-between" w="100%" grow={isMobile}>
                <Button
                  variant="filled"
                  color="red"
                  size="md"
                  radius="md"
                  onClick={handleCloseQuickSwap}
                  disabled={createSwap.isPending}
                >
                  Cancel
                </Button>
                <Button
                  size="md"
                  radius="md"
                  leftSection={<IconArrowsExchange size={16} />}
                  onClick={handleConfirmQuickSwap}
                  loading={createSwap.isPending}
                  disabled={!quickSwapSourceId || quickSwapSourceOptions.length === 0}
                >
                  Send request
                </Button>
              </Group>
            </>
          ) : null}
        </Stack>
      </Modal>
    </Stack>
  );
};

export default ScheduleOverviewPage;
